    uint32_t seed = static_cast<uint32_t>(src1.read_lane(wf, lane));
    uint32_t src_base =
        wf.vgpr_alloc().base +
        *Isa::resolved_vgpr_offset(wf, src0.opr_type_, src0.encoding_value_, src0.vgpr_msb_role());
